  to { opacity: 1; transform: translateX(-50%) translateY(0); }
}

@keyframes burst-out {
  0% { opacity: 0; transform: scale(0.15); }
  30% { opacity: 1; }
  100% { opacity: 0; transform: scale(3); }
}

@keyframes shrink-in {
  to { opacity: 0; transform: scale(0.05); filter: blur(25px); }
}

@media (max-width: 768px) {
