  progress.value = 45;
  updateTip();
  await new Promise(r => setTimeout(r, 500));
  progress.value = 75;
  updateTip();
  await new Promise(r => setTimeout(r, 500));
  progress.value = 100;
  updateTip();

  setTimeout(() => {
    isComplete.value = true;
