      <circle class="draw-circle inner" cx="300" cy="300" r="170" stroke="rgba(255,156,195,0.5)" />
      <g v-for="i in 8" :key="'heart-'+i" :transform="`rotate(${i * 45} 300 300)`">
        <path class="deco-heart" d="M300,30 C308,22 320,28 320,40 C320,28 332,22 340,30 C340,42 320,55 320,55 C320,55 300,42 300,30Z" transform="translate(0,-20)" fill="rgba(255,156,195,0.6)" filter="url(#pinkGlow)"/>
      </g>
      <g v-for="i in 12" :key="'star-'+i" :transform="`rotate(${i * 30} 300 300)`">
        <polygon class="deco-star" points="300,-252 303,-245 310,-243 304,-238 306,-230 300,-234 294,-230 296,-238 290,-243 297,-245" fill="rgba(255,230,150,0.7)" filter="url(#pinkGlow)"/>
      </g>
      <polygon class="draw-poly" points="300,30 570,300 300,570 30,300" />
      <polygon class="draw-poly star" points="300,80 360,230 520,230 390,320 430,480 300,400 170,480 210,320 80,230 240,230" />
    </svg>

    <div class="summoning-stars">
      <div
        v-for="i in 8"
        :key="i"
        class="summon-star"
        :class="{ lit: progress >= 25 + i * 9, 'fully-lit': progress >= 100 }"
        :style="starStyle(i - 1)"
      >
        <div class="star-glow"></div>
        <svg class="star-shape" viewBox="0 0 24 24">
          <polygon points="12,2 14.5,9 22,9 16,13.5 18.5,21 12,16.5 5.5,21 8,13.5 2,9 9.5,9" fill="currentColor"/>
        </svg>
      </div>
    </div>

    <svg class="constellation-lines" viewBox="0 0 600 600" :style="constellationOpacity">
      <polyline :points="starPointsPolyline(8, 260)" />
      <polyline :points="starPointsPolyline(8, 200)" />
    </svg>

    <div class="summoning-text">
      <div class="summon-title">{{ tip }}</div>
      <div class="summon-sub">{{ progressText }}</div>
    </div>

    <div class="sparkle-container">
      <div v-for="i in 20" :key="'spk-'+i" class="sparkle" :style="sparkleStyle(i)"></div>
    </div>

    <div class="burst-overlay"></div>
  </section>
</template>

<script setup>
import { ref, computed, onMounted, onUnmounted } from 'vue';
import { DataEngine } from '../engines/data/DataEngine.js';
import { useVideoBackground } from '../composables/useVideoBackground.js';

const emit = defineEmits(['done']);
const baseUrl = import.meta.env.BASE_URL;

const progress = ref(0);
const tip = ref('正在召唤守护星座…');
const progressText = ref('');
const isComplete = ref(false);
const videoLoaded = ref(null);
const loadingVideo = ref(null);

const { shouldUseVideo } = useVideoBackground();

function onVideoLoaded() {
  videoLoaded.value = true;
}

function onVideoError(e) {
  console.warn('[LoadingPhase] 视频加载失败，降级:', e);
  videoLoaded.value = false;
}

const tips = [
  { at: 0, title: '✨ 正在召唤守护星座…', sub: 'SUMMONING GUARDIAN CONSTELLATIONS' },
  { at: 35, title: '🌸 星辰连线中…', sub: 'STARS ALIGNING' },
  { at: 65, title: '💫 次元能量汇聚…', sub: 'DIMENSIONAL ENERGY CHARGING' },
  { at: 90, title: '🌟 门即将开启…', sub: 'THE GATE AWAKENS' },
  { at: 100, title: '🎀 次元之门已开启', sub: 'GATE OPENED' }
];

const starfield = ref(null);
const sakuraCanvas = ref(null);
let starRafId = null;
let sakuraRafId = null;
let starResizeHandler = null;

const constellationOpacity = computed(() => ({
  opacity: progress.value >= 50 ? Math.min((progress.value - 50) / 40, 1) : 0
}));

function starStyle(i) {
  const angle = (i / 8) * 360 - 90;
  return {
    '--angle': `${angle}deg`,
    '--light-delay': `${i * 0.15}s`,
    '--star-color': ['#ff9cc3', '#c9b1ff', '#87ceeb', '#ffe066', '#ff9cc3', '#c9b1ff', '#87ceeb', '#ffe066'][i]
  };
}

function sparkleStyle(i) {
  const x = Math.random() * 100;
  const y = Math.random() * 100;
  const delay = Math.random() * 4;
  const dur = 2 + Math.random() * 3;
  const size = 4 + Math.random() * 8;
  return {
    left: `${x}%`,
    top: `${y}%`,
    '--spk-delay': `${delay}s`,
    '--spk-dur': `${dur}s`,
    '--spk-size': `${size}px`
  };
}

function starPointsPolyline(count, radius) {
  const points = [];
  for (let i = 0; i <= count; i++) {
    const angle = ((i % count) / count) * Math.PI * 2 - Math.PI / 2;
    const x = 300 + Math.cos(angle) * radius;
    const y = 300 + Math.sin(angle) * radius;
    points.push(`${x},${y}`);
  }
  return points.join(' ');
}

function updateTip() {
  let current = tips[0];
  for (const t of tips) {
    if (progress.value >= t.at) current = t;
  }
  tip.value = current.title;
  progressText.value = current.sub;
}

function drawStar5(ctx, cx, cy, outerR, innerR, rot) {
  ctx.beginPath();
  for (let i = 0; i < 5; i++) {
    const outerAngle = rot + (i * 4 * Math.PI) / 5 - Math.PI / 2;
    const innerAngle = rot + ((i * 4 + 2) * Math.PI) / 5 - Math.PI / 2;
    const ox = cx + Math.cos(outerAngle) * outerR;
    const oy = cy + Math.sin(outerAngle) * outerR;
    const ix = cx + Math.cos(innerAngle) * innerR;
    const iy = cy + Math.sin(innerAngle) * innerR;
    if (i === 0) ctx.moveTo(ox, oy);
    else ctx.lineTo(ox, oy);
    ctx.lineTo(ix, iy);
  }
  ctx.closePath();
  ctx.fill();
}

function drawHeart(ctx, cx, cy, s, rot) {
  ctx.save();
  ctx.translate(cx, cy);
  ctx.rotate(rot);
  ctx.scale(s / 10, s / 10);
  ctx.beginPath();
  ctx.moveTo(0, 3);
  ctx.bezierCurveTo(-8, -5, -10, -10, -5, -12);
  ctx.bezierCurveTo(-2, -13, 0, -10, 0, -8);
  ctx.bezierCurveTo(0, -10, 2, -13, 5, -12);
  ctx.bezierCurveTo(10, -10, 8, -5, 0, 3);
  ctx.closePath();
  ctx.fill();
  ctx.restore();
}

function initStarfield() {
  const canvas = starfield.value;
  if (!canvas) return;
  const ctx = canvas.getContext('2d');
  let width = canvas.width = window.innerWidth;
  let height = canvas.height = window.innerHeight;

  const pastelColors = ['#ff9cc3', '#c9b1ff', '#87ceeb', '#ffe066', '#ffb3d9', '#a8e6cf', '#ffd3b6'];
  const particles = Array.from({ length: 200 }, () => {
    const shapes = ['star5', 'diamond', 'heart', 'dot'];
    return {
      x: Math.random() * width,
      y: Math.random() * height,
      size: Math.random() * 4 + 1.5,
      alpha: Math.random() * Math.PI * 2,
      speed: Math.random() * 0.01 + 0.004,
      drift: (Math.random() - 0.5) * 0.2,
      rise: -Math.random() * 0.15 - 0.05,
      shape: shapes[Math.floor(Math.random() * shapes.length)],
      color: pastelColors[Math.floor(Math.random() * pastelColors.length)],
      rot: Math.random() * Math.PI * 2,
      rotSpeed: (Math.random() - 0.5) * 0.015
    };
  });

  function resize() {
    width = canvas.width = window.innerWidth;
    height = canvas.height = window.innerHeight;
  }
  starResizeHandler = resize;
  window.addEventListener('resize', resize);

  function draw() {
    ctx.clearRect(0, 0, width, height);
    for (const p of particles) {
      p.alpha += p.speed;
      p.rot += p.rotSpeed;
      p.x += p.drift;
      p.y += p.rise;
      if (p.y < -20) { p.y = height + 20; p.x = Math.random() * width; }
      if (p.x < -20) p.x = width + 20;
      if (p.x > width + 20) p.x = -20;
      const opacity = (Math.sin(p.alpha) + 1) / 2 * 0.6 + 0.15;
      ctx.globalAlpha = opacity;
      ctx.fillStyle = p.color;
      ctx.shadowColor = p.color;
      ctx.shadowBlur = 6;
      if (p.shape === 'star5') drawStar5(ctx, p.x, p.y, p.size, p.size * 0.4, p.rot);
      else if (p.shape === 'heart') drawHeart(ctx, p.x, p.y, p.size, p.rot);
      else if (p.shape === 'diamond') {
        ctx.save();
        ctx.translate(p.x, p.y);
        ctx.rotate(p.rot);
        ctx.beginPath();
        ctx.moveTo(0, -p.size);
        ctx.lineTo(p.size * 0.5, 0);
        ctx.lineTo(0, p.size);
        ctx.lineTo(-p.size * 0.5, 0);
        ctx.closePath();
        ctx.fill();
        ctx.restore();
      } else {
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.size * 0.4, 0, Math.PI * 2);
        ctx.fill();
      }
      ctx.shadowBlur = 0;
    }
    ctx.globalAlpha = 1;
    starRafId = requestAnimationFrame(draw);
  }
  draw();
}

function initSakura() {
  const canvas = sakuraCanvas.value;
  if (!canvas) return;
  const ctx = canvas.getContext('2d');
  let width = canvas.width = window.innerWidth;
  let height = canvas.height = window.innerHeight;

  const petals = Array.from({ length: 35 }, () => ({
    x: Math.random() * width,
    y: Math.random() * height - height,
    size: Math.random() * 8 + 6,
    speed: Math.random() * 1 + 0.5,
    sway: Math.random() * 2 + 1,
    swaySpeed: Math.random() * 0.02 + 0.01,
    swayPhase: Math.random() * Math.PI * 2,
    rot: Math.random() * Math.PI * 2,
    rotSpeed: (Math.random() - 0.5) * 0.03,
    opacity: Math.random() * 0.4 + 0.3,
    hue: Math.random() > 0.5 ? '#ffb3d9' : '#ffcce6'
  }));

  function resize() {
    width = canvas.width = window.innerWidth;
    height = canvas.height = window.innerHeight;
  }
  window.addEventListener('resize', resize);

  function drawPetal(ctx, x, y, s, rot, color) {
    ctx.save();
    ctx.translate(x, y);
    ctx.rotate(rot);
    ctx.scale(s / 8, s / 8);
    ctx.beginPath();
    ctx.moveTo(0, -6);
    ctx.bezierCurveTo(5, -8, 8, -3, 0, 6);
    ctx.bezierCurveTo(-8, -3, -5, -8, 0, -6);
    ctx.fillStyle = color;
    ctx.fill();
    ctx.beginPath();
    ctx.moveTo(0, -6);
    ctx.quadraticCurveTo(0, 0, 0, 6);
    ctx.strokeStyle = 'rgba(255,255,255,0.3)';
    ctx.lineWidth = 0.3;
    ctx.stroke();
    ctx.restore();
  }

  function draw() {
    ctx.clearRect(0, 0, width, height);
    for (const p of petals) {
      p.y += p.speed;
      p.swayPhase += p.swaySpeed;
      p.x += Math.sin(p.swayPhase) * p.sway * 0.5;
      p.rot += p.rotSpeed;
      if (p.y > height + 20) {
        p.y = -20;
        p.x = Math.random() * width;
      }
      if (p.x < -20) p.x = width + 20;
      if (p.x > width + 20) p.x = -20;
      ctx.globalAlpha = p.opacity;
      drawPetal(ctx, p.x, p.y, p.size, p.rot, p.hue);
    }
    ctx.globalAlpha = 1;
    sakuraRafId = requestAnimationFrame(draw);
  }
  draw();
}

onMounted(async () => {
  initStarfield();
  initSakura();
  updateTip();

  await DataEngine.load();
  progress.value = 45;
  updateTip();
  await new Promise(r => setTimeout(r, 500));
  progress.value = 75;
  updateTip();
  await new Promise(r => setTimeout(r, 500));
  progress.value = 100;
  updateTip();

  setTimeout(() => {
    isComplete.value = true;
    setTimeout(() => emit('done'), 900);
  }, 600);
});

onUnmounted(() => {
  if (starRafId) cancelAnimationFrame(starRafId);
  if (sakuraRafId) cancelAnimationFrame(sakuraRafId);
  if (starResizeHandler) window.removeEventListener('resize', starResizeHandler);
  if (loadingVideo.value) {
    loadingVideo.value.pause?.();
    loadingVideo.value.src = '';
  }
});
</script>

